CREATE OR REPLACE FUNCTION fpb_kep_get_keep_share (as_recno char , as_case char ) RETURNS bigint AS $body$
DECLARE

ldc_amt bigint;
ldc_amt_not bigint;

BEGIN

  SELECT sc_kep_t_monthly_receive_det.money_amount,
         sc_kep_t_monthly_receive_det.money_amount_not
  INTO STRICT    ldc_amt , ldc_amt_not
    FROM sc_kep_t_monthly_receive,
         sc_kep_t_monthly_receive_det
   WHERE ( sc_kep_t_monthly_receive_det.membership_no = sc_kep_t_monthly_receive.membership_no ) and ( sc_kep_t_monthly_receive_det.receive_year = sc_kep_t_monthly_receive.receive_year ) and ( sc_kep_t_monthly_receive_det.receive_month = sc_kep_t_monthly_receive.receive_month ) and ( sc_kep_t_monthly_receive_det.seq_no = sc_kep_t_monthly_receive.seq_no ) and
         ( sc_kep_t_monthly_receive.receipt_no = as_recno  AND  sc_kep_t_monthly_receive_det.keeping_type_code = 'MS00' );

  case trim(both as_case )
    when 'money_amount' then
      if coalesce(ldc_amt::text, '') = '' then ldc_amt := 0;end if;
      return ldc_amt;
    when 'money_amount_not' then
      if coalesce(ldc_amt_not::text, '') = '' then ldc_amt_not := 0;end if;
      return ldc_amt_not;
    end case;


END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
